mapper.select:
SELECT COUNT(*) FROM project
                WHERE title = #{title}
                AND status = 'K1'

SELECT COUNT(*) FROM project
                WHERE identifier = #{identifier}
                AND status = 'K1'

SELECT COUNT(*) FROM project
WHERE identifier = #{identifier}
  AND status = 'K1'
  AND id != #{projectId}

SELECT COUNT(*) FROM project
WHERE title = #{title}
  AND status = 'K1'
  AND id != #{projectId}

SELECT p.id, p.title, p.identifier, p.user_id AS pmId, u.name AS pmName, p.end_date AS endDate, p.is_lock AS isLock, p.parent_id AS parentId, (LEVEL - 1) AS "level" FROM project p LEFT JOIN users u ON u.id = p.user_id WHERE p.status = 'K1'
AND p.id = #{id}
AND p.user_id = #{pmId}
AND p.end_date >= #{startDate}
AND p.end_date < #{endDate} + 1
AND p.is_lock = 'L0'
START WITH p.parent_id IS NULL CONNECT BY PRIOR p.id = p.parent_id ORDER SIBLINGS BY p.id DESC

mapper.update:
UPDATE project
SET is_lock = 'L1'
WHERE id = #{id}

UPDATE project
SET is_lock = 'L0'
WHERE id = #{id}

UPDATE project p
SET p.status = 'K0'
WHERE p.id = #{id}
AND NOT EXISTS(
    SELECT 1
    FROM project child
    WHERE child.parent_id = #{id}
    AND child.status != 'K0'
)

mapper.select:
SELECT default_version_id
FROM project
WHERE id = #{projectId}

mapper.update:
UPDATE project
SET default_version_id = #{versionId}
WHERE id = #{projectId}

