mapper.select:
SELECT v.id AS versionId, v.name AS versionName, v.status AS versionStatus, v.end_date AS endDate, v.description, v.project_id AS projectId, t.id AS taskId, t.title AS taskTitle, t.type AS taskType, t.workflow AS taskWorkflow, t.status AS taskStatus, t.progress FROM version v LEFT JOIN task t ON t.version_id = v.id AND t.status = 'T1' WHERE v.project_id IN ( SELECT p.id FROM project p WHERE p.status = 'K1' AND p.is_lock = 'L0'
START WITH p.id = #{projectId} CONNECT BY PRIOR p.id = p.parent_id
AND p.id = #{projectId}
) AND v.is_delete = 'F0'
AND v.status = #{versionStatus}
AND v.id = #{versionId}
AND t.type = #{taskType}
ORDER BY v.end_date ASC
